def solve(grid):
    import numpy as np
    grid = np.array(grid)
    H, W = grid.shape
    output = grid.copy()

    # Find divider column: column with same non-zero value in all non-empty rows
    divider_col = None
    divider_color = None
    best_count = 0
    for c in range(W):
        col_vals = grid[:, c]
        non_zero = col_vals[col_vals != 0]
        if len(non_zero) > 0 and len(set(int(x) for x in non_zero)) == 1:
            if len(non_zero) > best_count:
                divider_col = c
                divider_color = int(non_zero[0])
                best_count = len(non_zero)

    # Determine pattern side
    left_content = sum(1 for r in range(H) for c in range(divider_col) if grid[r,c] != 0)
    right_content = sum(1 for r in range(H) for c in range(divider_col+1, W) if grid[r,c] != 0)

    if left_content > 0 and right_content == 0:
        pattern_side = 'left'
    elif right_content > 0 and left_content == 0:
        pattern_side = 'right'
    else:
        pattern_side = 'left'  # default

    for r in range(H):
        if pattern_side == 'left':
            # Read pattern from divider outward (right to left)
            pattern = [int(grid[r, c]) for c in range(divider_col - 1, -1, -1)]
            proj_cols = list(range(divider_col + 1, W))
        else:
            # Read pattern from divider outward (left to right)
            pattern = [int(grid[r, c]) for c in range(divider_col + 1, W)]
            proj_cols = list(range(divider_col - 1, -1, -1))

        # Find segments (contiguous same-color non-zero runs)
        segments = []  # (color, length, start_distance_from_divider)
        i = 0
        while i < len(pattern):
            if pattern[i] != 0:
                color = pattern[i]
                start = i
                while i < len(pattern) and pattern[i] == color:
                    i += 1
                length = i - start
                segments.append((color, length, start + 1))  # start+1 = 1-indexed distance
            else:
                i += 1

        # Sort by distance from divider (closer first = lower start_d)
        segments.sort(key=lambda s: s[2])

        # Fill projection columns
        for d_idx, col in enumerate(proj_cols):
            d = d_idx + 1  # 1-indexed distance from divider
            for color, period, start_d in segments:
                if (d - 1) % period == 0:
                    output[r, col] = color
                    break  # closer segment has priority, stop at first match

    return output.tolist()

# Test on training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        for r in range(len(result)):
            if result[r] != expected[r]:
                print(f"  Row {r}: got {result[r]}")
                print(f"         exp {expected[r]}")

